1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCH_THRESHOLD = 5;
5	const HIGH_ENCH_RATE = 0.3;
6	const BLOCK_SIZE = 3;
7	const BLOCK_PREMIUM = 60;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	
20	const COMPONENT_TYPES = ["rune", "moonstone"];
21	
22	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
23	
24	const sum = (values: number[]): number =>
25	  values.reduce((total, value) => total + value, 0);
26	
27	const sumOfBasePremiums = (items: Item[]): number =>
28	  sum(items.map((item) => BASE_PREMIUMS[item.type]));
29	
30	const groupByType = (items: Item[]): Item[][] => {
31	  const groups: Record<string, Item[]> = {};
32	  for (const item of items) {
33	    if (!groups[item.type]) groups[item.type] = [];
34	    groups[item.type].push(item);
35	  }
36	  return Object.values(groups);
37	};
38	
39	const basePremiumForComponentGroup = (group: Item[]): number =>
40	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumOfBasePremiums(group);
41	
42	const basePremiumFor = (items: Item[]): number => {
43	  const components = items.filter(isComponent);
44	  const nonComponents = items.filter((item) => !isComponent(item));
45	  const componentGroupPremiums = groupByType(components).map(basePremiumForComponentGroup);
46	  return sum(componentGroupPremiums) + sumOfBasePremiums(nonComponents);
47	};
48	
49	const surchargeFor = (
50	  items: Item[],
51	  rate: number,
52	  applies: (item: Item) => boolean,
53	): number =>
54	  sum(items.map((item) => (applies(item) ? BASE_PREMIUMS[item.type] * rate : 0)));
55	
56	const isCursed = (item: Item): boolean => item.cursed === true;
57	const isHighlyEnchanted = (item: Item): boolean =>
58	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
59	
60	const quotePremium = (items: Item[]): number => {
61	  const base = basePremiumFor(items);
62	  const curseSurcharge = surchargeFor(items, CURSE_RATE, isCursed);
63	  const highEnchSurcharge = surchargeFor(items, HIGH_ENCH_RATE, isHighlyEnchanted);
64	  return Math.ceil(base + curseSurcharge + highEnchSurcharge + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
65	};
66	
67	export const runScenario = (scenario: any): unknown => {
68	  const items = scenario.steps[0].items;
69	  return { results: [{ premium: quotePremium(items) }] };
70	};
