const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
  const base = basePremiumFor(items);
  const curseSurcharge = surchargeFor(items, CURSE_RATE, isCursed);
  const highEnchSurcharge = surchargeFor(items, HIGH_ENCH_RATE, isHighlyEnchanted);
  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? base * LOYALTY_RATE : 0;
  return Math.ceil(base + curseSurcharge + highEnchSurcharge - loyaltyDiscount + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
  return { results: [{ premium: quotePremium(items, yearsWithMHPCO) }] };
};
